window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["map"]={"updatedAt":"2026-06-30","count":110,"nodes":[{"id":"nam-tieu-tinh-cau-thien-van","name":"Năm tiểu tinh cầu (Thiên Vận Tinh)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Năm tiểu tinh cầu phụ cận Thiên Vận Tinh, nơi tu sĩ kéo về chủ tinh chúc thọ.","detail":"Năm tiểu tinh cầu vây quanh Thiên Vận Tinh, là địa bàn phụ thuộc của các tu sĩ và lão quái trong vùng. Khi đại thọ ngàn năm của Thiên Vận Tử mở ra, tu sĩ từ năm tiểu tinh cầu này kéo về chủ tinh dự yến.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0460"]},{"id":"son-mon-thien-van-tong","name":"Sơn môn Thiên Vận Tông","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Sơn môn của Thiên Vận Tông trên Thiên Vận Tinh, cách thạch lâm khoảng ba mươi vạn dặm về hướng tây.","detail":"Nơi mở thọ yến ngàn năm cho sư tôn Thiên Vận Tử. Khu vực Tử tông được mây lớn ngưng tụ cứng như mặt đất bao phủ; bàn tiệc bày tiên quả sơn tửu náo nhiệt, là điểm Vương Lâm lao tới để báo thù.","theLucLienQuan":["Thiên Vận Tông","Tử tông"],"nguon":["@c0461"]},{"id":"tien-gioi","name":"Tiên giới","capDo":"gioi-dien","parentId":null,"blurb":"Cõi Tiên được nhắc đã bị hủy diệt; Dẫn Tiên thuật vẫn tiếp dẫn người lên Tiên giới, dấy lên nghi vấn nơi chốn.","detail":"Tiên giới được nhắc tới như cõi đã bị hủy diệt, phá toái. Khi Thiên Vận Tử thi triển Dẫn Tiên thuật tiếp dẫn người lên Tiên giới, đám tu sĩ kinh ngạc thắc mắc Tiên giới đã hủy diệt thì người bị đưa đi sẽ đến đâu, là Tiên giới phá toái hay một nơi chưa ai từng đặt chân.","theLucLienQuan":[],"nguon":["@c0468"]},{"id":"hac-mac-tinh","name":"Hắc Mặc Tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Trần Đào cướp được Thất thải lưu ly quang từ ba con thượng phẩm hoang thú.","detail":"Một tinh cầu nơi Trần Đào trong thời gian rèn luyện ở tinh ngoại đã đoạt được đoá Thất thải lưu ly quang từ ba con thượng phẩm hoang thú, rồi mang về dâng cho Thiên Vận Tử.","theLucLienQuan":[],"nguon":["@c0470"]},{"id":"yeu-tinh","name":"Yêu Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Trần Đào từng ở hơn năm trăm năm và rút Long cân từ xác một con yêu long.","detail":"Địa danh dạng tinh cầu nơi Trần Đào ở hơn năm trăm năm; tại đây hắn rút Long cân ra từ xác một con yêu long đã chết, luyện thành pháp bảo khốn trói.","theLucLienQuan":[],"nguon":["@c0471"]},{"id":"tong-tong-ba-ngon-nui-thien-van","name":"Tổng tông Thiên Vận (ba ngọn núi)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Tổng tông Thiên Vận Tông đặt tại Thiên Vận Tinh, vùng thiên địa đẹp hơn tiên cảnh với ba ngọn núi cao chọc trời.","detail":"Tổng tông là một vùng thiên địa đẹp hơn tiên cảnh, có ba ngọn núi cao chọc trời tạo bức tranh sơn thủy đen trắng chấn thiên kinh địa. Ngọn giữa thật phủ bạch tuyết Cửu U chi hàn; hai ngọn hai bên đen tuyền với tuyết đen rơi xuống nhưng là giả do Chân huyễn pháp của Thiên Vận Tử dựng nên. Đây là nơi đệ tử chân chính tế bái Tổ linh và nhận Cấm pháp thần thông.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0472"]},{"id":"the-gioi-bay-mau","name":"Thế giới bảy màu","capDo":"khac","parentId":null,"blurb":"Cảnh giới vô biên vô tận mở ra trong tâm thần Thiên Vận Tử, chứa 3600 (thực ra 3601) Thiên Vận Tử tu luyện các Cấm pháp thần thông khác nhau.","detail":"Không gian mở ra từ ánh sáng bảy màu trên tay Thiên Vận Tử, nơi Vương Lâm bước vào để chọn thần thông theo cơ duyên. Có 3600 Thiên Vận Tử giống hệt nhau, mỗi người tu luyện/chiến đấu một loại Cấm pháp thần thông; trong đó ẩn một Thiên Vận Tử áo xám — ‘hơn một người’, là thực thể thứ 3601.","theLucLienQuan":[],"nguon":["@c0474"]},{"id":"dia-tinh","name":"Địa Tinh","cn":"","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, màu vàng, hầu như toàn đất liền.","detail":"Địa Tinh là một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, màu vàng, nhiều quầng sáng, kích cỡ xấp xỉ Chu Tước Tinh, hầu như toàn đất liền ít đại dương. Trên Địa Tinh có Huyền Uyên Phái (Lục cấp tu chân quốc duy nhất) và Linh Nhạc quốc (Ngũ cấp tu chân quốc) cách nhau khoảng trăm vạn dặm.","theLucLienQuan":["Huyền Uyên Phái","Linh Nhạc quốc"],"nguon":["@c0476"]},{"id":"linh-nhac-quoc-map","name":"Linh Nhạc quốc","cn":"","capDo":"quoc-gia","parentId":"dia-tinh","blurb":"Ngũ cấp tu chân quốc nhỏ phía Tây Địa Tinh, nổi danh đặc sản Tý Linh vật.","detail":"Linh Nhạc quốc nằm cách Huyền Uyên Phái khoảng trăm vạn dặm về phía Tây trên Địa Tinh, là Ngũ cấp tu chân quốc nhỏ chỉ có bốn tông phái nhưng đặc sản Tý Linh vật nổi danh khắp Địa Tinh; là nơi Vương Lâm tới nhậm chức sứ giả.","theLucLienQuan":["Linh Nhạc quốc"],"nguon":["@c0476"]},{"id":"dia-ma-bac-gioi","name":"Địa Ma Bắc Giới","capDo":"khac","parentId":"dia-tinh","blurb":"Hiểm địa phía sau tấm bia đá lớn khắc bốn chữ đỏ đầy sát khí ở Cực Bắc Địa Tinh, nơi Vương Lâm tu Sát Lục Tiên quyết. (+) Khu vực phủ sương mù mỏng, chứa nhiều yêu thú, là nơi có Diệu Kim quả được yêu thú thủ hộ. [CAN-SOAT-GOP]","detail":"Khu vực phía sau tấm bia đá lớn khắc bốn chữ đỏ đầy sát khí Địa Ma Bắc Giới, đặt ở Cực Bắc Địa Tinh. Quanh bia quái phong gào thét; phía sau là dãy núi liên miên vô tận, mặt đất phủ lá thối, âm hàn yên tĩnh. Vương Lâm chọn nơi đây làm chốn tu luyện Sát Lục Tiên quyết vì công pháp cần giết chóc mới lĩnh ngộ.","theLucLienQuan":[],"nguon":["@c0478","@c0479"],"aliases":["#dia-ma-bac-gioi-c0479"]},{"id":"huyet-tinh","name":"Huyết Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu bên ngoài Thiên Vận Tinh do Huyết Tổ Diêu Tinh Hải độc chiếm, khai hoang nạp huyết tu luyện ma công.","detail":"Huyết Tổ độc chiếm và cải tạo cả tinh cầu này thành nơi nạp huyết tu luyện ma công; hai người phụ nữ của lão (gồm con gái Diêu Tích Tuyết) quanh năm cư ngụ ở đây, không tiếp xúc người ngoài, không ai dám chọc.","theLucLienQuan":["Huyết Tổ Diêu Tinh Hải","Diêu Tích Tuyết"],"nguon":["@c0486"]},{"id":"nam-pho-tinh-thien-van","name":"Năm phó tinh ngoài Thiên Vận Tinh","cn":"","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Năm tinh cầu phụ có mặt đất bao quanh Thiên Vận Tinh; Huyền Uyên phái đặt một tòa truyền tống trận khổng lồ trên một trong số đó.","detail":"Một trong năm phó tinh là nơi Huyền Uyên phái dựng truyền tống trận pháp khổng lồ, do mấy trăm đệ tử phóng linh lực phối hợp tiên ngọc khởi động để đưa người tới Đông Hải Yêu Linh.","theLucLienQuan":["Huyền Uyên Phái"],"nguon":["@c0486"]},{"id":"the-gioi-dong-hai-yeu-linh","name":"Thế giới Đông Hải yêu linh","capDo":"gioi-nho","parentId":"dong-hai-yeu-linh-chi-mon","blurb":"Thế giới hỗn độn tự hình thành bên trong cánh cửa Đông Hải yêu linh.","detail":"Bên trong cánh cửa Đông Hải yêu linh là một thế giới hỗn độn tự hình thành, có trời đất biển giống thế giới phàm nhân, không giống nơi thí luyện trọng bảo. Thí luyện kéo dài năm trăm năm; người vừa vào bị một lực kỳ dị đẩy tản ra khắp nơi. Vương Lâm rơi xuống một vùng hoang nguyên.","theLucLienQuan":["Thiên Vận Tông","Đại La kiếm tông"],"nguon":["@c0491"]},{"id":"dai-la-tinh","name":"Đại La tinh","capDo":"tinh-cau","parentId":null,"blurb":"Đại tinh cầu Lăng Thiên Hậu đưa từ tinh không tới, nơi đặt Đại La kiếm tông.","detail":"Một đại tinh cầu Lăng Thiên Hậu đưa từ tinh không tới và đặt tên Đại La tinh, lớn hơn năm đại phó tinh gấp mấy lần, linh lực sung túc. Đây là nơi đặt Đại La kiếm tông; đông bộ là chỗ Lăng Thiên Hậu phá cương phong vào bế quan luyện hóa Tiên kiếm.","theLucLienQuan":["Đại La kiếm tông"],"nguon":["@c0491"]},{"id":"binh-nguyen-hoang-vu-dong-hai-yeu-linh","name":"Bình nguyên hoang vu","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Vùng đồng bằng rộng lớn yên tĩnh, không có sinh mạng, Vương Lâm bay qua mất mười ngày.","detail":"Bình nguyên hoang vu trong vùng Đông Hải yêu linh, khắp nơi yên tĩnh, không có sinh mạng nào ngoài Vương Lâm. Hắn quét thần thức không thấy gì kỳ dị, bay liền mười ngày mới ra tới rìa và phát hiện vùng núi non phía xa.","theLucLienQuan":[],"nguon":["@c0492"]},{"id":"vung-nui-non-trung-diep-dong-hai-yeu-linh","name":"Vùng núi non trùng điệp","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Khu rừng núi cây cối xanh biếc ngoài rìa bình nguyên hoang vu, có dã thú và người xích lõa sinh sống.","detail":"Vùng núi non trùng điệp cây cối xanh biếc nằm ngoài rìa bình nguyên hoang vu. Trong rừng có dã thú lớn không linh lực và những người nửa xích lõa ẩn thân săn bắt. Bên trong vùng có một sơn cốc được trận pháp thượng cổ bảo vệ.","theLucLienQuan":[],"nguon":["@c0492"]},{"id":"co-yeu-thanh","name":"Cổ yêu thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Một trong những thành trì của Thiên Yêu quận, nơi Âu Dương Hoa từng học tập đạt trình độ nhất tinh; xa nhất lão từng đi tới. (+) Tòa thành trì rất lớn nằm ngoài ba ngàn dặm tính từ sơn cốc, nơi Âu Dương Hoa thuở nhỏ từng học tập. [CAN-SOAT-GOP]","detail":"Tòa thành lớn cách sơn cốc bộ tộc Âu Dương Hoa hơn ba ngàn dặm. Âu Dương Hoa thuở nhỏ từng học tập ở đó nên có tuổi thọ rất cao. Lão khẳng định thứ Vương Lâm cần tìm không có ở bộ tộc mình mà có thể tìm thấy tại Cổ yêu thành, định hướng mục tiêu hành trình tiếp theo của Vương Lâm.","theLucLienQuan":[],"nguon":["@c0493","@c0496","@c0565"],"aliases":["#co-yeu-thanh-thien-yeu-quan"]},{"id":"thien-yeu-quan-map","name":"Thiên Yêu quận","cn":"","capDo":"chau","parentId":"dong-hai-yeu-linh","blurb":"Một trong chín quận của thiên hạ nơi yêu linh; quận nơi sơn cốc của Vương Lâm tọa lạc, thuộc nơi man hoang ở rìa.","detail":"Thiên Yêu quận là một trong chín quận của thiên hạ nơi yêu linh, do yêu đế Tai Hư cùng bát đại yêu soái cai quản. Quận có thiên vạn yêu binh và hơn trăm thành trì, trong đó Cổ yêu th��nh là một trong những thành trì. Sơn cốc hình hồ lô của bộ lạc Âu Dương Hoa nằm ở vùng man hoang ở rìa của quận này.","theLucLienQuan":["Thiên Yêu quận","Bộ lạc sơn cốc (Âu Dương Hoa)"],"nguon":["@c0496"]},{"id":"dong-hai-yeu-linh","name":"Đông Hải yêu linh (nơi yêu linh)","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Vùng yêu linh rộng lớn có tổng cộng chín quận; mỗi đêm trăng tròn là đêm yêu linh đi săn mồi.","detail":"Đông Hải yêu linh, hay nơi yêu linh, là một vùng rộng lớn được chia thành tổng cộng chín quận trong thiên hạ. Mỗi khi trăng tròn chính là đêm yêu linh, lúc đó yêu linh ra ngoài đi săn mồi, chỉ ở trong trận pháp mới được bình an. Khoảng năm trăm năm lại có người từ bên ngoài tiến vào, mỗi lần đều gây gió tanh mưa máu; những người này gia nhập các quận, lấy chiến công thăng tiến và thường có biến hóa thần kỳ.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0496","@c0601"]},{"id":"vung-dat-yeu-linh","name":"Vùng đất yêu linh","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Vùng bí cảnh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh; năm ngàn năm mở một lần.","detail":"Vùng đất yêu linh chia làm mười quận, mỗi quận phong ấn một Cổ yêu chi linh. Cứ năm ngàn năm vùng mở một lần; dân cư gốc dù chiến công cao chỉ được cúng bái mà không thể dung hợp, chỉ người từ ngoài đến mới có cơ hội, và mấu chốt là yêu lực phải đủ. Người ngoài vào phải giết đối phương, hấp thu toàn bộ yêu lực để bớt đối thủ cạnh tranh.","theLucLienQuan":["Thiên Quỷ Đạo"],"nguon":["@c0502","@c0612","@c0565","@c0562"],"aliases":["Yêu Linh chi địa","Yêu Linh địa","Yêu linh chi địa"]},{"id":"cuu-tuyet-quan","name":"Cửu Tuyệt quận","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Quận trong vùng đất yêu linh có cổ yêu sinh ra sớm nhất, đến nay chưa ai dung hợp được.","detail":"Một trong chín quận của vùng đất yêu linh; cổ yêu nơi đây sinh ra sớm nhất nên hùng mạnh khó tưởng tượng, đến nay chưa ai dung hợp được.","theLucLienQuan":[],"nguon":["@c0502"]},{"id":"co-yeu-thanh-dia-danh","name":"Cổ Yêu thành (địa danh)","cn":"","capDo":"thanh","parentId":"dong-hai-yeu-linh","blurb":"Thành lớn ở Yêu Linh chi địa có phủ Tả Dực tướng quân; nơi lão áo trắng làm chấp sự.","detail":"Có quân chế với Tả Dực tướng quân thống lĩnh; trong phủ có hàng Trưởng lão tu vi ngang Vương Lâm. Người từ bên ngoài tới có thể tìm chức vụ trong phủ Tướng quân.","theLucLienQuan":["Cổ Yêu thành / phủ Tả Dực tướng quân"],"nguon":["@c0507"]},{"id":"yeu-linh-chi-dia","name":"Yêu linh chi địa (chín quận Yêu linh)","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng đất rộng lớn gồm chín quận Yêu linh với vô số bộ lạc lớn nhỏ; hệ cảnh giới tính theo giáp.","detail":"Vùng đất Yêu linh có vô số bộ lạc lớn nhỏ trải rộng, chia thành chín quận. Hệ cảnh giới ở đây tính theo giáp: ba sao bằng một giáp, ba giáp Trúc Cơ, ba mươi giáp Kết Đan, ba trăm giáp Nguyên Anh, ba nghìn giáp Hóa Thần, ba vạn giáp Anh Biến, ba mươi vạn giáp Vấn Đỉnh. Có hai loại chức vụ: chức trong (Chấp sự, Trưởng lão — không binh quyền) và chức ngoài (Đô thống, thống lĩnh — có binh quyền). Thiên Yêu quận với Cổ Yêu thành nằm trong vùng này.","theLucLienQuan":["Cổ Yêu thành"],"nguon":["@c0509","@c0562"],"aliases":["Vùng đất Yêu Linh","Yêu linh chi địa"]},{"id":"vuc-sau-thuy-trieu","name":"Vực sâu nơi thủy triều","aliases":["Nơi đó"],"capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Vực sâu nơi thủy triều trong Yêu Linh chi địa, mục tiêu Diêu Tích Tuyết nhiều lần xông vào.","detail":"Mục tiêu mà Diêu Tích Tuyết cố xông vào theo kế hoạch của phụ thân; muốn tiến sâu cần tu vi ít nhất Vấn Đỉnh kỳ. Nàng đã thử bốn lần đều dừng ở cùng một vị trí. Phụ thân nàng cùng Thiên Vận tử từng tới vực sâu nơi thủy triều này sau khi hỏi được bí mật từ Yêu Đế, suy đoán nơi đó sáu phần là thật.","theLucLienQuan":[],"nguon":["@c0517"]},{"id":"lanh-tho-yeu-linh","name":"Lãnh thổ Yêu Linh","capDo":"vuc","parentId":null,"blurb":"Vùng đất rộng lớn bao gồm chiến trường cổ và Thiên Yêu quận.","detail":"Lãnh thổ Yêu Linh là vùng đất bao trùm nhiều khu vực, trong đó có chiến trường cổ hung danh hiển hách ở phía Tây và Thiên Yêu quận có kinh thành cùng Yêu Đế.","theLucLienQuan":["Thiên Yêu quận","Yêu Vệ"],"nguon":["@c0530"]},{"id":"luyen-hon-coc","name":"Luyện Hồn cốc (sơn cốc Vương Lâm dưỡng hồn)","capDo":"khac","parentId":null,"blurb":"Sơn cốc nơi Vương Lâm ngồi dưỡng hồn và truyền công pháp cho Thập Tam; chiến trường cổ nằm ở phía Tây ngoài cốc.","detail":"Sơn cốc gắn với bộ tộc Luyện Hồn, nơi Vương Lâm truyền sáu tầng Cự Linh Cửu Tu cho Thập Tam rồi ngồi một mình dưỡng hồn dưới hắc vụ do Tôn Hồn Phiên hóa thành. Phía Tây ngoài cốc, xa hơn cả Thiên Yêu quận, là chiến trường cổ trong lãnh thổ Yêu Linh.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0530"]},{"id":"kinh-thanh-thien-yeu-quan","name":"Kinh thành Thiên Yêu quận","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Kinh đô Thiên Yêu quận, được ví đầm rồng hang hổ; điểm đến của Vương Lâm và Mạc Lực Hải sau khi rời Cổ Yêu thành.","detail":"Nơi tập trung các thế lực lớn trong quận, trong đó có nhánh Thiên Vận Tông tới lãnh thổ Yêu Linh và mười người Đại La Kiếm Tông mà Vương Lâm muốn truy hỏi về nơi Chu Dật bị phong ấn. Vương Lâm và Mạc Lực Hải tới đây qua ba truyền tống trận xuất phát từ Cổ Yêu thành.","theLucLienQuan":["Thiên Yêu quận","Cổ Yêu điện","Thiên Vận Tông","Đại La Kiếm Tông"],"nguon":["@c0531"]},{"id":"thien-yeu-thanh","name":"Thiên Yêu thành","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Kinh thành Thiên Yêu quận, do chín tòa thành nhỏ ghép thành, sáng sớm phủ long khí.","detail":"Kinh thành của Thiên Yêu quận, nằm phía bắc Thiên Yêu quận nơi nhiều đồng bằng đan xen, nhìn từ trên cao như chín con Cự Long quấn lấy nhau, đầu chín con rồng đều hướng về đầm Long Đàm. Thành thực chất do chín thành nhỏ ghép lại: tám thành ngoài phân theo bát quái, thành giữa là Đế Đô. Sáng sớm cả thành phủ một lớp sương mỏng từ chín dãy núi, được Yêu Đế gọi là long khí. Ngoài thành đặt mười tám truyền tống trận.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"de-do-thien-yeu-thanh","name":"Đế Đô","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Thành trung tâm Thiên Yêu thành, tẩm cung của Yêu Đế.","detail":"Tòa thành giữa của Thiên Yêu thành, là tẩm cung của Yêu Đế. Có sông bao quanh và tám cây cầu đá nối ra tám thành ngoài, bên trong đầy lầu các điêu lan ngọc thế. Là nơi diễn ra cuộc chiến Yêu tướng cứ ba trăm năm một lần.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"hong-thanh-thien-yeu","name":"Hồng thành","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Thành ngoài cửa tây (vòng ngoài) của Thiên Yêu thành, nơi đặt phủ của Mạc Lệ Hải.","detail":"Một trong bốn thành vòng ngoài Vũ–Trụ–Hồng–Hoang, thuộc cửa tây của Thiên Yêu thành, là nơi đặt phủ của Yêu tướng Mạc Lệ Hải. Thành sầm uất; con đường lớn có một phần ba ở giữa là quân đạo dành riêng cho quân đội.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"huyen-thanh-thien-yeu","name":"Huyền thành","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Một trong tám thành ngoài Thiên Yêu Thành; có Huyền Thành soái phủ (phủ phó soái Huyền Thành). (+) Thành ngoài cửa tây (vòng trong) của Thiên Yêu thành. [CAN-SOAT-GOP]","detail":"Một trong bốn thành vòng trong Thiên–Địa–Huyền–Hoàng, thuộc cửa tây của Thiên Yêu thành, ở phía trong so với Hồng thành.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532","@c0537"],"aliases":["#huyen-thanh-thien-yeu-quan"]},{"id":"the-gioi-mau-mau-hong-lao","name":"Thế giới màu máu","aliases":["Thế giới máu tầng đáy Hồng lao"],"capDo":"khac","parentId":"hong-lao","blurb":"Thế giới độc lập màu máu do đế quân tự chế tạo ở tầng đáy Hồng lao, đầy hồ máu nuôi sát lục khí cho yêu kiếm.","detail":"Tầng dưới cùng của Hồng lao là một thế giới độc lập màu máu, do đế quân tự tay tạo ra. Khắp nơi là hồ máu, mỗi hồ chứa hàng ngàn người ngâm nửa thân, ngày đêm thổ nạp. Theo chu kỳ, toàn bộ người trong các hồ máu bừng tỉnh hô “Sát!” rồi lao vào chém giết lẫn nhau; người chết lại sống dậy từ hồ máu, thực chất chỉ là công cụ giết chóc. Sát lục khí sinh ra bị bầu trời hút đi, dồn về nuôi yêu kiếm ngân long của yêu đế. Vương Lâm tu luyện sát lục chi tâm tại đây.","theLucLienQuan":["Hồng lao","Yêu đế"],"nguon":["@c0536"]},{"id":"the-gioi-huyet-sac-hong-lao","name":"Thế giới huyết sắc (Hồng Lao)","cn":"","capDo":"khac","parentId":"hong-lao","blurb":"Thế giới máu bên trong Hồng Lao, đầy hồ máu, tu sĩ tan-tái sinh hấp thu sát niệm; ngân long Đế Kiếm ngự trị.","detail":"Thế giới màu máu bên trong Hồng Lao, đầy hồ máu, tu sĩ liên tục tan thành huyết nhục rồi tái sinh trong hồ máu để hấp thu sát niệm — nơi luyện Sát Lục. Ngân long (Đế Kiếm) ngự trị hấp thu sát vụ chuyển thành sinh cơ. Bị Vương Lâm phá vỡ phạm vi lớn khi sát lục khí bạo phát.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"vu-thanh-thien-yeu-quan","name":"Vũ Thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Một trong các thành thuộc Thiên Yêu Thành; nơi Mặc Phi ở trong một biệt viện cùng hai đệ tử.","detail":"Vũ Thành là nơi Yêu Tương Mặc Phi ở trong một biệt viện cùng hai đệ tử đeo đại kiếm.","theLucLienQuan":["Thiên Yêu Quận","Hỏa Yêu Quận"],"nguon":["@c0537"]},{"id":"hoa-yeu-quan-map","name":"Hỏa Yêu Quận","cn":"","capDo":"khac","parentId":null,"blurb":"Một trong các quận thuộc lãnh thổ Yêu Linh; nơi Vương Lâm bị truyền tống lệch tới sau khi tiến Vấn Đỉnh. (+) Nơi Yêu Tướng Vu Sâm lấy sát lục tu luyện hằng năm. [CAN-SOAT-GOP]","detail":"Quận vùng Yêu Linh, nơi Yêu Tướng Vu Sâm — Yêu Tướng duy nhất không có thành trì — hằng năm lấy sát lục đạo tu luyện tới đỉnh.","theLucLienQuan":[],"nguon":["@c0543","@c0556"],"aliases":["#hoa-yeu-quan-556"]},{"id":"de-do-thien-yeu-thanh-554","name":"Đế Đô Thiên Yêu thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Tòa thành Đế Đô của Thiên Yêu quận tồn tại rất nhiều vạn năm, bị thiên uy thiên kiếp Vương Lâm nghiền nát hoàn toàn thành tro bụi, chỉ thánh vật Yêu Cổ sót lại.","detail":"Đế Đô Thiên Yêu thành là tòa thành Đế Đô của Thiên Yêu quận, sừng sững tồn tại rất nhiều vạn năm, có hoàng cung Đế Đô và quảng trường vạn trượng. Khi thiên kiếp giáng đòn trừng phạt thứ hai lên Vương Lâm, thiên uy nghiền nát hoàn toàn cả tòa thành thành tro bụi, đất đai chia năm xẻ bảy; duy nhất thánh vật Yêu Cổ sót lại. Năm lão già con cháu Cổ Yêu cũng từ lòng đất nơi đây phóng lên.","theLucLienQuan":["Thiên Yêu quận","Cổ Yêu"],"nguon":["@c0554"]},{"id":"ma-vuc-tinh-cau","name":"Ma Vực","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Tinh cầu Ma Vực trên Thiên Vận Tinh, nơi Mạc Tổ tu luyện.","detail":"Ma Vực là một tinh cầu nằm trên Thiên Vận Tinh, nơi cường giả Mạc Tổ tu vi Âm Dương Hư Thực nhị ý cư ngụ. Từ đây ba đệ tử thân truyền của Mạc Tổ xuất phát, trong đó hai người vượt mức tư cách vào mảnh đất Yêu Linh.","theLucLienQuan":["Mạc Tổ (sư đồ Ma Vực)"],"nguon":["@c0559"]},{"id":"thien-dat-thanh","name":"Thiên Dật Thành","cn":"","capDo":"thanh","parentId":"van-yeu-son","blurb":"Tòa thành của Hỏa Yêu quận trên sườn Vạn Yêu sơn, nơi tập kết mười vạn Yêu binh.","detail":"Thiên Dật Thành nằm trên một sườn của Vạn Yêu sơn, thuộc Hỏa Yêu quận. Trong thành có mười vạn Yêu binh chờ lệnh, hơn mười Yêu tướng đứng trên thành cùng Phó soái tọa trấn, làm cứ điểm cho trận vây diệt Vương Lâm.","theLucLienQuan":["Hỏa Yêu quận"],"nguon":["@c0560"]},{"id":"dung-hoa-thanh","name":"Dung Hỏa Thành","cn":"","capDo":"thanh","parentId":"van-yeu-son","blurb":"Tòa thành của Thiên Yêu quận trên sườn Vạn Yêu sơn, đối diện Thiên Dật Thành.","detail":"Dung Hỏa Thành nằm trên sườn núi đối diện thuộc Thiên Yêu quận, ngó sang Thiên Dật Thành của Hỏa Yêu quận qua dải Vạn Yêu sơn.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0560"]},{"id":"thien-van-thanh-pho-soai","name":"Thiên Văn Thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Thành trên Nhiễm Vân Tinh nơi Tôn Tích chạy tới sau khi tu luyện dưới đáy biển; có thành Bắc, thành Đông. (+) Nơi Phó soái Hỏa Yêu quận có chuyện riêng muốn đến trước khi bị giữ lại tọa trấn Vạn Yêu sơn. [CAN-SOAT-GOP]","detail":"Thiên Văn Thành là điểm đến mà Phó soái Hỏa Yêu quận dự định ghé vì chuyện riêng, nhưng vừa đến Vạn Yêu sơn thì nhận lệnh Yêu Đế phải ở lại mấy ngày diệt Vương Lâm. Chuyện riêng và mục đích của hắn tại đây chưa được tiết lộ.","theLucLienQuan":["Hỏa Yêu quận"],"nguon":["@c0560","@c0622"],"aliases":["#thien-van-thanh-nhiem-van-tinh"]},{"id":"thanh-tung-dao-hoa-yeu-quan","name":"Thành Tùng Đào (quận Hỏa Yêu)","cn":"","capDo":"thanh","parentId":"hoa-yeu-quan-556","blurb":"Thành biên giới quận Hỏa Yêu, đích đến của đại quân cánh tả quận Thiên Yêu và Vương Lâm.","detail":"Thành Tùng Đào nằm ở biên giới quận Hỏa Yêu, nơi Mặc Phi (nay là Phó soái) cùng cánh quân bên trái đang tiến tới. Đại quân cánh tả quận Thiên Yêu (ngàn vạn yêu binh, ba chính soái Thiên–Trụ–Hoang, ba phó soái Hồng–Huyền–Hoàng) cũng thẳng đến đây; Vương Lâm định tới tìm Mặc Phi.","theLucLienQuan":["Hỏa Yêu Quận","Thiên Yêu quận"],"nguon":["@c0570"]},{"id":"quan-hoa-yeu","name":"Quận Hỏa Yêu","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi người bộ lạc Luyện Hồn đến hấp thu hồn yêu binh đã chết để tu hành hiệu quả.","detail":"Nơi người bộ lạc Luyện Hồn đến hấp thu hồn của yêu binh đã chết để tu hành hiệu quả hơn; ai muốn đi phải qua khảo hạch đích thân của Âu Dương Hoa.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0573"]},{"id":"thanh-trang-chuong-khi-bien-gioi-hoa-yeu-kim-yeu","name":"Tòa thành trắng trong chướng khí (biên giới Hỏa Yêu - Kim Yêu)","cn":"","capDo":"thanh","parentId":null,"blurb":"Tòa thành bốn phía núi đá trắng cao khoảng mười trượng ẩn sâu trong dãy núi chướng khí biên giới quận Hỏa Yêu và Kim Yêu — sào huyệt của Lão tổ.","detail":"Vùng biên giới quận Hỏa Yêu và Kim Yêu có một dãy núi lớn quanh năm chướng khí, nơi cả quân Hỏa Yêu lẫn Kim Yêu đều không quản. Sâu trong chướng khí có tòa thành bốn phía núi đá trắng cao khoảng mười trượng, mang cảm giác thần bí — sào huyệt của Lão tổ, nơi ra lệnh truy bắt Vương Lâm.","theLucLienQuan":["Quận Hỏa Yêu","Quận Kim Yêu"],"nguon":["@c0574"]},{"id":"quan-do-thanh-co-yeu","name":"Quận đô thành Cổ Yêu","cn":"","capDo":"thanh","parentId":null,"blurb":"Nơi Vương Lâm mất tích hai mươi năm trước, theo lời bóng đen bẩm báo với Lão tổ.","detail":"Quận đô thành Cổ Yêu là nơi Vương Lâm — nay làm sứ giả Cổ Yêu — đã mất tích hai mươi năm trước. Thông tin này được thuộc hạ của Lão tổ tra ra và bẩm báo.","theLucLienQuan":["Cổ Yêu"],"nguon":["@c0574"]},{"id":"kim-yeu-quan","name":"Kim Yêu Quận","cn":"","capDo":"khac","parentId":null,"blurb":"Một trong chín quận; Liên minh tu sĩ nằm ở giao giới phía bắc của Hoả Yêu Quận và Kim Yêu Quận.","detail":"Một trong chín quận Yêu Linh. Theo lời khai của Tôn Vân Sơn, căn cứ Liên minh tu sĩ nằm ở chỗ giao nhau phía bắc của Hoả Yêu Quận và Kim Yêu Quận, nơi quanh năm ngập chướng khí, cực kỳ bí mật.","theLucLienQuan":["Tu sĩ Liên minh"],"nguon":["@c0576"]},{"id":"toa-thanh-trang-lao-to-lien-minh","name":"Toà thành màu trắng","cn":"","capDo":"thanh","parentId":null,"blurb":"Toà thành trắng sừng sững, đại bản doanh của Lão Tổ; nơi hơn trăm tu sĩ phiêu phù bên ngoài và Tiên vệ bay ra.","detail":"Phía trước Vương Lâm hiện ra một toà thành màu trắng sừng sững. Hơn trăm tu sĩ phiêu phù bên ngoài thành, khiếp sợ trước khí thế của Vương Lâm. Đây là đại bản doanh của Lão Tổ Liên minh — nơi các Tiên vệ áo đen bay ra nghênh chiến.","nguon":["@c0577"]},{"id":"de-do-hoa-yeu-quan","name":"Đế đô Hoả Yêu Quận","cn":"","capDo":"thanh","parentId":"hoa-yeu-quan-map","blurb":"Toà thành trống trải sau trăm năm chiến tranh, mặt đất đỏ lầy do máu, sương xám và yêu khí phủ kín.","detail":"Kinh đô Hoả Yêu Quận, từng phồn hoa ngang Thiên Yêu Thành. Sau gần trăm năm tử chiến với Thiên Yêu Quận, mặt đất nhuộm hồng bởi máu, đầy hài cốt và tử khí tạo thành sương mù xám phủ kín. Yêu Đế đã tự tham chiến khiến kinh đô trống không, chỉ còn lại Thánh địa Yêu Cốc; toàn bộ bị Cổ Yêu phong ấn bằng yêu mạc trải mười dặm ngoài thành.","theLucLienQuan":["Hoả Yêu Quận"],"nguon":["@c0584"]},{"id":"thanh-dia-yeu-coc-hoa-yeu-quan","name":"Thánh địa Yêu Cốc (Hoả Yêu Quận)","cn":"","capDo":"khac","parentId":"de-do-hoa-yeu-quan","blurb":"Thánh địa nằm sâu trong đế đô Hoả Yêu Quận, phần duy nhất còn lại khi kinh đô trống không.","detail":"Yêu Cốc của Hoả Yêu Quận nằm sâu trong đế đô; yêu khí dày đặc và tử khí tràn ngập toả ra từ đây khiến đế đô như toà thành trong sương mù. Đây là nơi Cổ Yêu Hoả Yêu Quận trú ngụ và phóng thần thức đối đầu Vương Lâm.","theLucLienQuan":["Hoả Yêu Quận"],"nguon":["@c0584"]},{"id":"trieu-tich-tham-uyen","name":"Triều Tịch thâm uyên","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Hiểm địa nhiều hung hiểm trong lời đồn, mục tiêu chung của cả nhóm; nghi nằm sau vết nứt trong vân hải.","detail":"Nơi hiểm địa nhiều hung hiểm theo lời đồn, được Đỗ Kiến nghi là nằm sau vết nứt mà hắn phát hiện trong vân hải tại Vân Vụ sơn hải. Vương Lâm đã tra xét trước bằng thủy tinh của Bối La, biết có mấy nơi với tu vi của hắn vẫn phải mạo hiểm.","theLucLienQuan":[],"nguon":["@c0589"]},{"id":"van-vu-son-hai","name":"Vân Vụ sơn hải","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Vùng mây mù đồ sộ mỹ lệ của Thủy Yêu quận, Đỗ Kiến khen hơn tiên giới một bậc; chứa vết nứt nghi là Triều Tịch thâm uyên.","detail":"Vùng mây mù đồ sộ mỹ lệ tại Thủy Yêu quận, được Đỗ Kiến khen còn hơn tiên giới một bậc. Trong vân hải có một vết nứt mà Đỗ Kiến phát hiện, nghi chính là Triều Tịch thâm uyên trong lời đồn.","theLucLienQuan":[],"nguon":["@c0589"]},{"id":"tang-da-truyen-tong-tran-c0605","name":"Tảng đá có Truyền Tống Trận","cn":"","capDo":"khac","parentId":"ho-sau-luc-hut-c0605","blurb":"Tảng đá nhô ra khoảng mười trượng dưới đáy hố, bên trên có một Truyền Tống Trận, thoáng hiện rồi chìm vào màn sương đen.","detail":"Tảng đá lớn nhô ra khoảng mười trượng dưới đáy hố sâu, bên trên có một Truyền Tống Trận. Nhờ thanh khí Lôi Long phát sáng, Vương Lâm thoáng thấy nó rồi tảng đá lại chìm vào màn sương đen, không kịp nhìn rõ — gợi ý một lối truyền tống ẩn dưới đáy vực.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"la-thien-tinh-vuc","name":"La Thiên tinh vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực rộng lớn rực rỡ tinh quang, không có môn phái, chỉ có các tu chân gia tộc huyết thống. (+) Tinh vực ở Vực Bắc nơi Huyễn Gia cư ngụ, gồm Ngũ Đại Tinh ở bắc vực; nơi Lôi tiên giới mở ra. (+) Tinh vực Vương Lâm đang đến, chia bốn phía đông tây nam bắc, có nhiều Tu Chân Tinh. (+) Tinh vực Vương Lâm dự định tới để đề cao tu vi, do nữ tử trong tranh dụ dẫn. [CAN-SOAT-GOP]","detail":"La Thiên tinh vực là nơi nữ tử trong tranh dụ Vương Lâm tới với mục đích riêng còn bỏ ngỏ. Vương Lâm chỉ tin nàng ba phần song vẫn quyết tới để đề cao tu vi cho ngang Thiên Vận Tử rồi quay về tra xét động phủ.","theLucLienQuan":[],"nguon":["@c0613","@c0616","@c0622","@c0615"],"aliases":["#la-thien-tinh-vuc-q06","#la-thien-tinh-vuc-615","#la-thien-tinh-vuc-q06-c0616"]},{"id":"dong-lam-tinh","name":"Đông Lâm tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Tôn Thái luân lạc gần trăm năm, có ba gia tộc Hứa-Lữ-Lưu cực mạnh. (+) Tinh cầu có Hướng gia mà Vương Lâm định ghé dò thân phận nữ tử trong tranh. (+) Tinh cầu nơi có Hướng gia, thuộc La Thiên tinh vực. [CAN-SOAT-GOP]","detail":"Đông Lâm tinh là nơi đặt Hướng gia. Vương Lâm dự định tới đây dò thân phận nữ tử trong tranh vì lão tổ tộc nàng được cho là có thể khiến Uyển nhi sống lại.","theLucLienQuan":["Hướng gia (Đông Lâm tinh)"],"nguon":["@c0613","@c0612","@c0625"],"aliases":["#dong-lam-tinh-map","#dong-lam-tinh-la-thien"]},{"id":"vuc-sau-trieu-tich-thuy-yeu-quan","name":"Vực sâu triều tịch (Thủy Yêu quận)","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Nơi Vương Lâm lao xuống; có lực hút mạnh đưa người tiến sâu vào hành lang dẫn tới hố sâu, dưới đáy hố có dòng xoáy.","detail":"Vực sâu triều tịch nằm tại Thủy Yêu quận, có lực hút cực mạnh đưa người tiến sâu vào hành lang dẫn tới hố sâu. Vương Lâm hòa hợp với lực hút này, dùng Thất Tinh kiếm trận tăng tốc lao xuống. Dưới đáy hố có dòng xoáy thông tới La Thiên tinh vực.","theLucLienQuan":[],"nguon":["@c0614"]},{"id":"la-van-tinh-vuc","name":"La Vân Tinh Vực","cn":"","capDo":"vuc","parentId":"tu-dai-tien-gioi","blurb":"Tinh vực thuộc Lôi chi tiên giới, nơi Vương Lâm hiện ra sau khi qua trận lốc xoáy như truyền tống trận.","detail":"Một tinh vực thuộc Lôi chi tiên giới trong tứ đại tiên giới phong-vũ-lôi-điện. Vương Lâm sau khi dung nhập trận lốc xoáy đã hiện ra tại tinh không xa lạ này, không phải Liên Minh Tinh Vực quê hương. Tại đây có những sinh vật như Minh vụ trùng toả sương độc; cũng là nơi sức mạnh Lôi hệ của hắn (Thiên Lôi từ Thái Cổ Lôi Long) phát huy uy lực.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615"],"aliases":["#la-van-tinh-vuc-615"]},{"id":"lien-minh-tinh-vuc","name":"Liên Minh Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực chứa Chu Tước tinh, Ám Nguyệt tinh; phạm vi hoạt động của Thi Âm Tông và Tứ Thánh tông. (+) Tinh vực quê hương của Vương Lâm, nơi đa số tu sĩ không biết tới các tinh vực bên ngoài. [CAN-SOAT-GOP]","detail":"Quê hương của Vương Lâm. Ở đây, trừ số rất ít người, đại đa số tu sĩ không biết sự tồn tại của các tinh vực bên ngoài, tưởng tinh không chỉ có Tu Chân Liên Minh — sự thật về tứ đại tiên giới bị giấu diếm.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0615","@c0625"],"aliases":["#lien-minh-tinh-vuc-625"]},{"id":"nhiem-van-tinh","name":"Nhiễm Vân Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu của Nhiễm gia; nơi Vương Lâm ép ba người nộp tiên ngọc, mục tiêu Huyễn Đông được phái tới. (+) Tu chân tinh nơi Nhiễm gia cư trú trong La Thiên Tinh Vực. [CAN-SOAT-GOP]","detail":"Một tu chân tinh thuộc La Thiên Tinh Vực, là nơi cư trú của Nhiễm gia. Bốn người được Vương Lâm cứu (Nhiễm Nguyệt, Nhiễm Thần, Nhiễm Phong và Tôn Tuyết Sơn) đều là người Nhiễm Vân Tinh đến thí luyện.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615","@c0627"],"aliases":["#nhiem-van-tinh-627","#nhiem-van-tinh-615"]},{"id":"tu-dai-tien-gioi","name":"Tứ đại tiên giới (Phong, Vũ, Lôi, Điện)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bốn mảnh tiên giới phân theo các thông đạo dẫn tới tiên vực viễn cổ, hình thành sau khi tiên vực bỏ rơi tu sĩ rời tinh không. (+) Bốn đại tiên giới phong, vũ, lôi, điện; mỗi giới có các tinh vực riêng. [CAN-SOAT-GOP]","detail":"Bốn đại tiên giới phong-vũ-lôi-điện, mỗi giới sở hữu các tinh vực riêng. Tu sĩ La Thiên Tinh Vực đa phần biết tới tầng bậc này, còn tu sĩ Liên Minh Tinh Vực thì hầu hết không hay. Lôi chi tiên giới — chứa La Vân Tinh Vực nơi Vương Lâm vừa đến — là một trong tứ đại tiên giới này.","theLucLienQuan":[],"nguon":["@c0615","@c0612"],"aliases":["#tu-dai-tien-gioi-612"]},{"id":"la-thien-tinh-vuc-map","name":"La Thiên tinh vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Quê hương nữ tử trong tranh, một mảnh tinh không vô số tu chân tinh nằm sau dòng xoáy; chính là Lôi tiên giới trong Tứ đại tiên giới.","detail":"La Thiên tinh vực là một thế giới khác gồm vô số tu chân tinh, nằm sau dòng xoáy ở đáy hố vùng yêu linh. Nơi này không có tông phái, chỉ có các gia tộc tu chân (như Hướng gia ở Đông Lâm tinh). La Thiên tinh vực chính là Lôi tiên giới — một trong Tứ đại tiên giới. Thiên Nghịch châu xuất hiện sớm nhất ở đây rồi quỷ dị biến mất.","theLucLienQuan":["Hướng gia (Đông Lâm tinh)"],"nguon":["@c0612"]},{"id":"tu-dai-tien-gioi-phong-vu-loi-dien","name":"Tứ đại tiên giới (Phong, Vũ, Lôi, Điện)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bốn mảnh tiên giới phân theo các thông đạo dẫn tới tiên vực viễn cổ, là chỗ tu sĩ cao giai phi thăng.","detail":"Xưa có một tiên vực thần bí, về sau bỏ rơi tu sĩ và rời tinh không, chỉ để lại các thông đạo phân thành Tứ đại tiên giới: Phong, Vũ, Lôi, Điện. La Thiên tinh vực chính là Lôi tiên giới; Vũ tiên giới thuộc Liên Minh Tinh Vực là nơi Thiên Nghịch châu từng xuất hiện sau khi biến mất ở La Thiên tinh vực. Đây là chỗ tu sĩ cao giai phi thăng.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"nhiem-van-tinh-la-thien","name":"Nhiễm Vân Tinh","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu màu thủy lam ở bình nguyên phía bắc La Thiên Tinh Vực, biển chiếm hơn nửa, linh lực tràn đầy.","detail":"Nhiễm Vân Tinh là tinh cầu màu thủy lam ở phía bắc La Thiên Tinh Vực, biển chiếm hơn nửa, linh lực tràn đầy hơn xa quê hương Chu Tước của Vương Lâm. Toàn tinh cầu chỉ có ba phương thế lực, mỗi thế lực một Vấn Đỉnh (một trung kỳ, hai sơ kỳ). Vương Lâm chọn nơi này ẩn nấp tránh đám Thiên Vận Tinh truy đuổi; thành Tôn gia nằm tại đây.","theLucLienQuan":["Nhiễm gia","Tôn gia"],"nguon":["@c0616"]},{"id":"thien-huyen-tinh","name":"Thiên Huyễn Tinh","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Một trong năm đại chủ tinh, lệ thuộc bắc vực Nhiễm Vân Tinh, là bắc vực chủ tinh La Thiên Tinh Vực. (+) Tinh cầu phía nam, nơi có tổ trạch Huyễn gia. [CAN-SOAT-GOP]","detail":"Thiên Huyễn Tinh là một trong năm đại chủ tinh, lệ thuộc bắc vực, xung quanh có nhiều sao lệ thuộc. Đây là bắc vực chủ tinh của La Thiên Tinh Vực, nơi có Huyễn gia và Hứa gia danh giá. Cái tên Thiên Huyễn khiến Vương Lâm nhớ tới Liễu Mi từng tu luyện Thiên Huyễn Vô Tình Đạo.","theLucLienQuan":["Huyễn gia","Hứa gia"],"nguon":["@c0616","@c0627"],"aliases":["#thien-huyen-tinh-627"]},{"id":"dong-lam-sat-tinh","name":"Đông Lâm Tinh","aliases":["Đông Lâm Sát Tinh","La Thiên Đông Vực","#dong-lam-sat-tinh-c0616"],"capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"La Thiên Đông Vực, còn gọi Đông Lâm Sát Tinh, nơi quỷ dị hư vô mờ mịt, ác mộng đè nặng dân La Thiên Tinh Vực.","detail":"Đông Lâm Tinh chính là La Thiên Đông Vực, còn có tên Đông Lâm Sát Tinh — nơi quỷ dị hư vô mờ mịt lúc hiện lúc ẩn. Người đi ra từ đó đều tàn nhẫn, từng có tu sĩ giết cả một gia tộc, là ác mộng đè nặng dân La Thiên Tinh Vực. Khi Vương Lâm hỏi về nơi này, bốn người dẫn đường đều tái nhợt hoảng loạn.","theLucLienQuan":[],"nguon":["@c0616"]},{"id":"ton-gia-thanh-nhiem-van","name":"Thành Tôn gia","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Tòa thành trì cự thạch xanh đề hai chữ Tôn gia trên Nhiễm Vân Tinh, nơi Vương Lâm ẩn nấp.","detail":"Thành Tôn gia là tòa thành trì cự thạch xanh đề hai chữ Tôn gia trên Nhiễm Vân Tinh. Thành chủ yếu là phàm nhân nhưng tu sĩ nhiều, phố xá bán vật dụng tu sĩ. Thành bắc yên tĩnh, linh khí dày, có nhiều người sống một mình, mỗi phòng có cấm chế phòng hộ; một ngọn núi đá ba trượng treo bảy tám lệnh bài đen làm động phủ cho thuê, có thanh niên Nguyên Anh kỳ canh giữ. Vương Lâm thuê phòng thứ năm phía tây ở đây.","theLucLienQuan":["Tôn gia"],"nguon":["@c0616"]},{"id":"thanh-dong-thanh-tu-si-c0618","name":"Thành đông (thành tu sĩ)","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu cuối thành tập trung cửa hàng lớn san sát, đa số tu sĩ lui tới, nơi đặt Bảo Hợp Lâu và Thanh Trúc Các.","detail":"Khu thành đông của một thành tu sĩ, cuối thành tập trung cửa hàng lớn san sát, đa số tu sĩ lui tới, dân thường ít. Tập tục nơi đây là đặt khối linh thạch lớn chưa luyện hóa trước cửa để phô trương sức mạnh. Nơi đặt Bảo Hợp Lâu và Thanh Trúc Các.","theLucLienQuan":["Bảo Hợp Lâu","Thanh Trúc Các"],"nguon":["@c0618"]},{"id":"thanh-bac-nui-da-c0618","name":"Thành bắc & núi đá ngoài thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu thành bắc với núi đá ngoài thành, nơi tu sĩ ngồi thổ nạp hấp thụ linh khí.","detail":"Khu thành bắc của thành tu sĩ, ngoài thành có núi đá nơi Vương Lâm và các tu sĩ ngồi thổ nạp hấp thụ linh khí.","theLucLienQuan":[],"nguon":["@c0618"]},{"id":"thanh-tay-c0618","name":"Thành tây (phường thị tự do)","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu thành tây có phường thị tự do mua bán pháp bảo, vật liệu, song tu sĩ Anh Biến trở lên hiếm.","detail":"Khu thành tây của thành tu sĩ, có phường thị tự do nơi tu sĩ mua bán pháp bảo, vật liệu, song tu sĩ Anh Biến trở lên hiếm, không phải nơi buôn bán tốt nhất.","theLucLienQuan":["Phường thị tự do thành tây"],"nguon":["@c0618"]},{"id":"thanh-bac-ton-gia-nhiem-van-tinh","name":"Thành Bắc (tòa thành Tôn Gia)","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Chỗ ở của Vương Lâm tại thành Bắc trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản.","detail":"Tòa thành nơi Vương Lâm trú tại thành Bắc trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản lý. Gần chỗ ở của hắn có ngọn núi nơi một nữ giả nam tĩnh tọa thổ nạp.","theLucLienQuan":["Tôn Gia"],"nguon":["@c0621"]},{"id":"thanh-ton-gia-nhiem-van-tinh","name":"Thành Tôn gia (chi nhánh)","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Khu thành có tòa nhà lớn của Tôn gia chi nhánh, nơi Vương Lâm đại náo và ép bồi thường.","detail":"Trung tâm thành Tôn gia có tòa nhà lớn của gia tộc (chi nhánh). Người trung niên chạy về đây kêu cứu rồi ngã gục; Vương Lâm đáp xuống điềm tĩnh, vung lốc xoáy cuốn văng tu sĩ Tôn gia và giáng uy áp khổng lồ lên tòa nhà lớn buộc cả gia tộc chống đỡ.","theLucLienQuan":["Tôn gia (chi nhánh)"],"nguon":["@c0620"]},{"id":"hai-duong-dong-bo-nhiem-van-tinh","name":"Hải dương đông bộ Nhiễm Vân Tinh","capDo":"khac","parentId":"nhiem-van-tinh-la-thien","blurb":"Biển cả bao la ở đông bộ Nhiễm Vân Tinh, nơi sâu nhất có nam tử tóc dài ẩn tu dưới đáy biển.","detail":"Đông bộ Nhiễm Vân Tinh có hải dương bao la. Nơi sâu nhất của biển cả, một nam tử tóc dài khoanh chân ngồi ẩn tu, mắt lóe tinh quang như hai ngọn đèn. Hắn cảm nhận sự xuất hiện của vị tu sĩ Vấn Đỉnh (Vương Lâm), nhìn không thấu tu vi đối phương, hiểu cái liếc cảnh cáo rồi rời đáy biển bay đi.","theLucLienQuan":[],"nguon":["@c0620"]},{"id":"thien-huyen-tinh-bac-vuc","name":"Thiên Huyễn Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06","blurb":"Tinh cầu giống ngọc lưu ly, một trong Ngũ Đại Tinh ở bắc vực, quê hương Huyễn Gia, đích đến của sư phụ và Liễu Mi. (+) Một trong năm đại chủ tinh, lệ thuộc bắc vực Nhiễm Vân Tinh; nơi đặt Huyễn gia và Hứa gia. [CAN-SOAT-GOP]","detail":"Tinh cầu trông giống ngọc lưu ly, là một trong Ngũ Đại Tinh ở bắc vực La Thiên Tinh Vực và là quê hương gia tộc Huyễn Gia. Sư phụ Liễu Mi đưa nàng về đây sau vài ngàn năm chưa quay lại, nhờ La Thiên Thạch của tổ tiên.","theLucLienQuan":["Huyễn Gia"],"nguon":["@c0622","@c0616"],"aliases":["#thien-huyen-tinh-bac-vuc-c0616"]},{"id":"loi-tien-gioi","name":"Lôi tiên giới","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc-q06","blurb":"Nơi mở định kỳ trên La Thiên Tinh Vực, có Lôi Đỉnh bị Lôi Tiên Điện khống chế; suất đi là điều kiện Tôn Tích đưa ra. (+) Tiên giới đã bị hủy, nơi tổ tiên Huyễn gia từng là tiên nhân và để lại huyết mạch. [CAN-SOAT-GOP]","detail":"Một thế giới mở định kỳ trên La Thiên Tinh Vực, bên trong có Lôi Đỉnh bị Lôi Tiên Điện khống chế. Mỗi lần mở chỉ người La Thiên Tinh Vực và gia tộc ghi chép trong Lôi Tiên Điện mới được tuyển chọn vào. Suất đi Lôi tiên giới trăm năm sau là điều kiện Tôn Tích đưa ra để cầu Vương Lâm trợ giúp.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0622","@c0631"],"aliases":["#loi-tien-gioi-da-huy"]},{"id":"am-nguyet-tinh","name":"Ám Nguyệt tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu ở Liên minh tinh vực, quê cũ Tôn Thái muốn gửi tro cốt về.","detail":"Nằm trong Liên minh tinh vực. Là quê cũ Tôn Thái — nơi có Thiên Sơn, dưới chân núi có thôn trang. Tôn Thái nhờ Vương Lâm mang tro cốt về đây để lá rụng về cội.","nguon":["@c0625"]},{"id":"van-ha-tinh","name":"Vân Hà tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06","blurb":"Tinh cầu bỏ đi không có tu sĩ, tràn ngập khói độc và chướng khí giết được tu sĩ; đích đến của Vương Lâm. (+) Tinh cầu phát hiện mỏ quáng Kim Viêm (mỏ đá lửa kim loại). [CAN-SOAT-GOP]","detail":"Tinh cầu thuộc La Thiên tinh vực, nơi phát hiện một mỏ quáng Kim Viêm — mỏ đá lửa kim loại, thiên tài địa bảo người người tranh đoạt. Vương Lâm chưa biết vị trí cụ thể, định nhờ tinh đồ La Thiên tinh vực để tìm tới đoạt mỏ.","theLucLienQuan":[],"nguon":["@c0628","@c0629"],"aliases":["#van-ha-tinh-q06"]},{"id":"thien-huyen-chu-tinh","name":"Thiên Huyễn chủ tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Chủ tinh nơi đặt Huyễn gia; xuất xứ của tộc vệ Huyễn Đông.","detail":"Chủ tinh là nơi đặt đại thế lực Huyễn gia. Huyễn Đông tự xưng là nhị phẩm tộc vệ của Huyễn gia trên Thiên Huyễn chủ tinh, được phái xuống Nhiễm Vân tinh diệt người tham dự.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0629"]},{"id":"van-ha-tinh-tu-chan-hoang-phe","name":"Vân Hà tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh cầu hoang phế màu xám thẫm phủ sương mù dày, có mỏ Kim Viêm và Vọng Nguyệt.","detail":"Tinh cầu tu chân hoang phế, màu xám thẫm phủ sương mù dày khiến thần thức không vào được và có tiếng rít gào cảnh cáo. Bên trong trời tối đen, mặt đất nứt nẻ mọc đầy xúc tu hư thối, tử khí đậm đặc do chính tinh cầu phát ra, các thành trì hoang tàn bị xúc tu bao vây. Nơi đây có mỏ Kim Viêm và mãnh thú Vọng Nguyệt; Vương Lâm nghi có xác Cổ Thần.","theLucLienQuan":[],"nguon":["@c0631"]},{"id":"thuy-yeu-quan-c0613","name":"Thủy Yêu quận","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Một trong chín quận Yêu Linh; nơi Vương Lâm dẫn đàn Văn thú tới để thu phục.","detail":"Thủy Yêu quận là quận Vương Lâm dẫn đàn Văn thú tới (thay vì Hỏa Yêu quận) mở túi trữ vật thu phục; nơi hơn hai phần ba Văn thú trưởng thành tự vẫn.","nguon":["@c0613"]},{"id":"vu-tien-gioi-lien-minh-tinh-vuc","name":"Vũ tiên giới (Liên Minh Tinh Vực)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Một trong Tứ đại tiên giới thuộc Liên Minh Tinh Vực, nơi Thiên Nghịch châu từng xuất hiện.","detail":"Vũ tiên giới là một trong Tứ đại tiên giới (Phong, Vũ, Lôi, Điện), thuộc Liên Minh Tinh Vực. Đây là nơi Thiên Nghịch châu lại xuất hiện sau khi quỷ dị biến mất khỏi La Thiên tinh vực.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"thanh-bac-nhiem-van-tinh-q06","name":"Thành Bắc (tòa thành Vương Lâm trú)","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh","blurb":"Tòa thành nơi Vương Lâm trú trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản.","detail":"Chỗ ở của Vương Lâm nơi thành Bắc trên Nhiễm Vân Tinh; linh khí nơi đây đậm đặc hơn ngoại thành, do Tôn Gia kiểm soát và Tôn Khải Minh phụ trách. Gần chỗ trú có một ngọn núi nơi người thanh niên nữ giả nam tĩnh tọa thổ nạp.","theLucLienQuan":["Tôn Gia"],"nguon":["@c0621"]},{"id":"ton-gia-thanh-nhiem-van-tinh-629","name":"Tôn gia thành","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh-627","blurb":"Tòa thành thuộc Tôn gia trên Nhiễm Vân tinh, nơi có người trẻ tuổi tu sĩ bị tiếng quát Huyễn Đông chấn thương.","detail":"Thành trì của Tôn gia trên Nhiễm Vân tinh. Dưới một núi đá ở thành có tu sĩ tu vi thấp đang thổ nạp, bị thanh âm như sấm của Huyễn Đông chấn động tâm mạch phun máu.","theLucLienQuan":["Tôn gia"],"nguon":["@c0629"]},{"id":"lo-chi-tien-gioi-633","name":"Lôi chi tiên giới","capDo":"gioi-dien","parentId":null,"blurb":"Tiên giới nơi một lão tổ bước hai của Huyễn gia chết trong cuộc tranh đoạt năm xưa.","detail":"Theo lời Tôn Tích, Huyễn gia từng có hai lão tổ tu vi bước hai (tu đạo); một trong số đó đã chết tại Lôi chi tiên giới trong cuộc tranh đoạt năm xưa, chỉ còn lại một lão tổ đủ uy lực quét ngang chúng sinh.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0633"]},{"id":"cai-khe-vach-da-ho-sau","name":"Cái khe trên vách đá phía dưới hố sâu","capDo":"khac","parentId":null,"blurb":"Nơi Vương Lâm tiến hành luyện chế Tiên Vệ.","detail":"Khe nứt trên vách đá phía dưới hố sâu, nơi Vương Lâm ẩn mình luyện chế Tiên Vệ. Bên ngoài có lực hút không ngừng và ngày càng mạnh suốt hơn nửa năm, tạo áp lực thời gian thúc Vương Lâm liều luyện chế.","theLucLienQuan":[],"nguon":["@c0608"]},{"id":"vuc-sau-day-vuc","name":"Vực sâu / hố sâu đáy vực","capDo":"khac","parentId":"chu-tuoc-tinh","blurb":"Nơi đấu pháp với lực cản cực mạnh; đáy có hố sâu vô hạn với lực hút khác thường, gần hành lang quay về.","detail":"Vương Lâm tháo chạy xuống vực sâu này để kéo giãn khoảng cách, đấu lôi pháp với đệ nhị nguyên thần Tham Lang. Lực cản bên dưới cực mạnh; đáy vực có hố sâu vô hạn phát ra lực hút khác thường mà Vương Lâm từng vào, biết vận tiên lực nương một bên lao xuống an toàn, gần hành lang quay về. Thái Cổ Lôi Long mới thức tỉnh lao theo nhưng không nắm quy luật lực hút nên giãy giụa phóng điện đánh vỡ vách đá.","theLucLienQuan":[],"nguon":["@c0604"]},{"id":"cai-khe-trong-vach-da","name":"Cái khe trong vách đá","capDo":"khac","parentId":"vuc-sau-day-vuc","blurb":"Miệng khe rộng chừng một trượng trong vách đá hố sâu, ít chịu lực hút, là chỗ Vương Lâm trú thân và nuốt Lôi Long.","detail":"Miệng khe rộng chừng một trượng trong vách đá vạn trượng của hố sâu; bên trong ít chịu lực hút bên ngoài. Vương Lâm phát hiện nhờ chỗ hụt của Tiên Kiếm và Loan Đao, lao vào trú thân, thu hồi pháp bảo rồi dùng thần thông thôn hồn nuốt và hấp thu Thái Cổ Lôi Long.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"tang-da-truyen-tong-tran-day-ho","name":"Tảng đá lớn có Truyền Tống Trận","capDo":"khac","parentId":"vuc-sau-day-vuc","blurb":"Tảng đá nhô ra khoảng mười trượng dưới đáy hố, bên trên có một Truyền Tống Trận, thoáng hiện rồi chìm vào sương đen.","detail":"Tảng đá lớn nhô ra khoảng mười trượng dưới đáy hố sâu, bên trên có một Truyền Tống Trận. Nhờ thanh khí Lôi Long phát sáng, Vương Lâm thoáng thấy nó rồi thanh quang yếu đi, tảng đá lại chìm vào màn sương đen; thần thức không tản ra được nên không nhìn rõ — gợi ý một lối truyền tống ẩn dưới đáy vực.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"ho-sau-luc-hut-thien-soai-dong-dung","name":"Hố sâu lực hút (đáy Thiên Soái Động Dung)","capDo":"khac","parentId":null,"blurb":"Hố sâu với vách đá vạn trượng dựng đứng sâu không thấy đáy, lực hút điên cuồng tăng mạnh càng xuống dưới.","detail":"Hố sâu nơi đáy Thiên Soái Động Dung, vách đá vạn trượng dựng đứng sâu không thấy đáy, có màn sương đen che phủ. Lực hút điên cuồng càng xuống càng mạnh như cơn gió lốc, có thể hút lệch cả lôi cầu, khiến thần thức không thể tản ra. Giữa hố có tảng đá lớn mang Truyền Tống Trận và cái khe lánh nạn trên vách.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"ho-sau-luc-hut-day-vach-da-van-truong","name":"Hố sâu lực hút","aliases":["Đáy vách đá vạn trượng"],"capDo":"khac","parentId":null,"blurb":"Hố sâu sâu không thấy đáy với lực hút mạnh dần theo độ sâu.","detail":"Hố sâu sâu không thấy đáy, vách đá vạn trượng dựng đứng; lực hút mạnh dần và tăng vọt theo độ sâu, hút mất cả lôi cầu của Thái Cổ Lôi Long. Thần thức không thể tản ra trong nơi này, khắp nơi phủ màn sương đen. Dưới đáy có tảng đá lớn mang Truyền Tống Trận và cái khe trong vách đá.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"ho-sau-vach-da-luc-hut","name":"Hố sâu lực hút cực mạnh","capDo":"khac","parentId":null,"blurb":"Hố sâu vạn trượng sâu không thấy đáy, lực hút càng xuống càng mạnh, có sương đen che thần thức.","detail":"Hố sâu sâu không thấy đáy, vách đá vạn trượng dựng đứng; lực hút càng xuống càng mạnh, mạnh dần như gió lốc, hút cả lôi cầu lẫn người và rồng vào trong; màn sương đen che phủ khiến thần thức không thể tản ra.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"suong-tim-yeu-linh","name":"Sương tím (tử vụ Yêu Linh)","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng sương mù tím chỉ vào được không ra được, lối ra duy nhất bị bầy yêu thú vây.","detail":"Vùng sương tím (tử vụ) thuộc mảnh đất Yêu Linh, có đặc tính chỉ vào được không ra được. Lối ra duy nhất bị đàn yêu thú kỳ dị vây quanh, phải phá vây mới thoát. Khi bị Tham Lang kích hoạt bẫy, sương tím co lại cực nhanh và sinh ra Tử khí ăn mòn ở rìa, hấp thu cả kiếm khí khiến đệ tử Đại La kiếm tông bị kẹt lại, mất nhiều tinh lực.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0600"]},{"id":"manh-dat-yeu-linh","name":"Mảnh đất Yêu Linh","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng đất nơi có sư đệ của Thần Long ở ngoài sương tím.","detail":"Mảnh đất Yêu Linh — nơi có các sư đệ của Thần Long ở bên ngoài làn sương tím, khiến hắn lo lắng cho họ khi bàn việc phá vây.","theLucLienQuan":[],"nguon":["@c0600"]},{"id":"the-gioi-truyen-thua-co-than","name":"Thế giới truyền thừa của Cổ thần","cn":"","capDo":"khac","parentId":null,"blurb":"Tinh cầu thần bí nơi Vương Lâm từng thấy vô số Văn thú bên ngoài.","detail":"Thế giới truyền thừa của Cổ thần, một tinh cầu thần bí mà Vương Lâm hồi tưởng khi thấy vô số Văn thú bên ngoài sương tím. Chính nhờ trải nghiệm nơi đây, Vương Lâm không những nhận biết mà còn rất tinh tường về Văn thú.","theLucLienQuan":[],"nguon":["@c0600"]},{"id":"vuc-sau-vach-da","name":"Vực sâu (vách đá vực sâu)","capDo":"khac","parentId":"manh-dat-yeu-linh","blurb":"Vực sâu có vách đá nơi Tham Lang đánh tay vào để hút lục khí thi triển Phệ Tử Nhất Thức.","detail":"Vách đá vực sâu là nơi Tham Lang đánh tay vào để hút vô số lục khí tràn ra như thác nước xanh biếc cho thần thông Phệ Tử Nhất Thức, thôn phệ thần thông của đối phương.","theLucLienQuan":[],"nguon":["@c0602"]},{"id":"vien-co-chien-truong","name":"Viễn cổ chiến trường","cn":"远古战场","aliases":["Chiến trường viễn cổ"],"capDo":"vuc","parentId":null,"blurb":"Chiến trường cổ xưa, nơi xuất xứ phần lớn hồn phách anh linh mà Hổ Bào thu thập.","detail":"Hồn phách tại đây là anh linh tu sĩ cổ đại, tu vi trước khi chết không yếu, có cả hồn phách cấp yêu suất.","theLucLienQuan":[],"nguon":["@c0562"]},{"id":"thien-van-tinh","name":"Thiên Vận tinh","cn":"天运星","aliases":[],"capDo":"tinh-cau","parentId":null,"blurb":"Nơi Lăng Thiên Hậu và Thiên Vận Tử là đại thần thông nổi danh.","detail":"Thiên Vận tinh là nơi Kiếm Tôn Lăng Thiên Hậu và Thiên Vận Tử nổi danh là đại thần thông.","theLucLienQuan":["Kiếm Tôn"],"nguon":["@c0564"]},{"id":"chien-truong-vien-co","name":"Chiến trường viễn cổ","capDo":"khac","parentId":null,"blurb":"Nơi có bảo tháp chứa áo giáp ma cổ xưa; lão già hắc y được lệnh ngăn Vương Lâm tiến đến đây.","detail":"Một địa danh cổ xưa nơi đặt bảo tháp chứa áo giáp ma đã thiếu một hộ uyển, bên trong tỏa u quang và có thần niệm ra lệnh. Áo giáp ban ba kiện ma giáp cho lão già hắc y (Người hầu Tôn Ma) cùng mệnh lệnh ngăn không cho Vương Lâm tiến đến chiến trường viễn cổ. Đây là điểm đến mà Vương Lâm đang hướng tới khi bị các Yêu Vệ truy cản.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"van-yeu-son","name":"Vạn Yêu sơn","cn":"萬妖山","capDo":"khac","parentId":null,"blurb":"Ngọn núi Vương Lâm vượt qua trên đường truy tìm tiếng hừ lạnh.","detail":"Một dãy núi mà Vương Lâm bay vượt qua khi truy theo tiếng hừ lạnh, dẫn đến cánh đồng hoang đầy hài cốt nơi Địa Ma phục kích hắn.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"canh-dong-hoang-hai-cot","name":"Cánh đồng hoang đầy hài cốt","capDo":"khac","parentId":null,"blurb":"Vùng đất nứt nẻ đầy hài cốt, nơi Yêu Vệ Địa Ma phục kích Vương Lâm.","detail":"Một vùng đất hoang nứt nẻ, chất đầy hài cốt và bốc mùi khó chịu. Tại đây Yêu Vệ Địa Ma chui từ lòng đất lên tấn công Vương Lâm bằng đất nhọn và vây hắn trong thần thông Thiên Nùng (Thiên Trướng Địa Đông), tạo nên một quả cầu khổng lồ giam giữ.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"hac-thap","name":"Hắc tháp","cn":"黑塔","capDo":"khac","parentId":null,"blurb":"Tòa tháp đen nơi có kẻ mặc áo giáp u quang quan sát, kinh sợ về Chưởng ấn của Vương Lâm.","detail":"Một tòa tháp đen ẩn chứa tồn tại mặc áo giáp tỏa u quang. Kẻ này quan sát trận chiến của Vương Lâm và kinh sợ khi thấy Chưởng ấn vô danh của hắn có bảy phần tương tự thần thông của ‘người kia’ — một nhân vật bí ẩn khiến hắn run sợ.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"thien-ha-cuu-quan","name":"Thiên hạ cửu quận","cn":"天下九郡","capDo":"khac","parentId":null,"blurb":"Vùng đất gồm chín quận, nơi có hắc lao tàn khốc nhất mà Hổ Bào nhắc đến.","detail":"Khu vực rộng lớn bao gồm chín quận. Trong thiên hạ cửu quận có hắc lao — nhà tù tàn khốc nhất — nơi Hổ Bào dọa sẽ phong ấn hồn phách Vương Lâm rồi ném thân thể hắn vào để hành hạ mỗi ngày.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"tieu-tinh-ban-phe","name":"Tiểu tinh bán phế","cn":"小星","aliases":["Tiểu tinh của bản tôn tóc hồng"],"capDo":"tinh-cau","parentId":null,"blurb":"Tiểu tinh bán phế cách Đông Hải chi môn vô số dặm, nơi bản tôn tóc hồng hấp thu linh lực sâu lòng đất.","detail":"Tiểu tinh bán phế là một tinh cầu nằm cách Đông Hải chi môn vô số dặm, nơi bản tôn tóc hồng của Vương Lâm trú ngụ. Thông qua dẫn dắt nguyên thần, bản tôn tóc hồng mở mắt, đánh ấn quyết, hô “Thu” để hút linh lực sâu trong lòng đất, hô ứng đồng bộ với hành động của Vương Lâm tại Yêu Linh chi địa.","theLucLienQuan":[],"nguon":["@c0565"]},{"id":"dong-hai-chi-mon","name":"Đông Hải chi môn","cn":"東海之門","aliases":[],"capDo":"khac","parentId":null,"blurb":"Mốc tham chiếu khoảng cách định vị tiểu tinh bán phế của bản tôn tóc hồng.","detail":"Đông Hải chi môn là một địa danh được dùng làm mốc tham chiếu khoảng cách: tiểu tinh bán phế nơi bản tôn tóc hồng của Vương Lâm trú ngụ nằm cách Đông Hải chi môn vô số dặm.","theLucLienQuan":[],"nguon":["@c0565"]},{"id":"hoa-yeu-quan","name":"Hỏa Yêu quận","cn":"火妖郡","aliases":[],"capDo":"chau","parentId":null,"blurb":"Nơi có thi thể Tử Thử và kiếm khí Vương Lâm bỏ lại.","detail":"Hỏa Yêu quận là một quận nơi còn lưu thi thể của Tử Thử, vốn vẫn nhớ vị trí. Vương Lâm tiếc nuối đã bỏ lại kiếm khí của mình tại đây, tính sau quay lại truy hồi.","theLucLienQuan":[],"nguon":["@c0565"]},{"id":"hac-lao-thien-ha-cuu-quan","name":"Hắc lao (thiên hạ cửu quận)","cn":"","capDo":"khac","parentId":null,"blurb":"Nhà tù tàn khốc nhất thiên hạ cửu quận mà Hổ Bào tuyên bố sẽ ném Vương Lâm vào để hành hạ.","detail":"Hắc lao được Hổ Bào mô tả là nhà tù tàn khốc nhất trong thiên hạ cửu quận. Hổ Bào tuyên bố sẽ phong ấn hồn phách Vương Lâm rồi ném vào hắc lao này, sau đó rút hồn nhốt vào hồn phiên để hành hạ mỗi ngày.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"de-thap-quan","name":"Đệ thập quận","cn":"第十郡","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Quận thứ mười mà Hổ Bào dự định lập ra tại vùng đất Yêu Linh để làm yêu đế, chưa thành hiện thực do Hổ Bào bị diệt.","detail":"Hổ Bào tuyên bố sẽ thu thập trăm vạn hồn phách để mở ra đệ thập quận tại vùng đất Yêu Linh và đảm nhận chức yêu đế. Kế hoạch này thất bại khi Hổ Bào bị Vương Lâm tiêu diệt.","theLucLienQuan":[],"nguon":["@c0562"]},{"id":"hac-lao","name":"Hắc lao","capDo":"khac","parentId":null,"blurb":"Lao ngục đen nơi Hổ Bào từng bị giam, ngộ ra ý chí phản Vương Lâm.","detail":"Hổ Bào kể trong hắc lao đã ngộ ra phải mạnh hơn Vương Lâm rồi giết hắn, vì từng bị biến thành quân cờ và bị người khác giận chó đánh mèo.","theLucLienQuan":[],"nguon":["@c0562"]},{"id":"thanh-tri-giap-ranh-thien-yeu-quan","name":"Thành trì giáp ranh Thiên Yêu quận","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Tòa thành trì nằm ở biên giới Thiên Yêu quận, nơi Vương Lâm ngộ đạo Hoàng Tuyền và thu phục mười Yêu Tướng.","detail":"Thành trì giáp ranh Thiên Yêu quận là nơi Vương Lâm — đang ở cảnh giới Vấn Đỉnh sơ kỳ — đứng trên tường thành cảm ngộ mười năm rồi đột nhiên hóa đạo niệm thành dòng sông Hoàng Tuyền, đạt rìa thiên đạo bước hai. Tại đây hắn cuốn mười Yêu Tướng xuống hoàng tuyền theo luân hồi của chính mình, đồng thời khiến Phó soái Hỏa Yêu quận đang trấn thủ tường thành kinh hãi bỏ chạy về Đế Đô bằng khúc xương đen truyền tống.","theLucLienQuan":["hoa-yeu-quan"],"nguon":["@c0561"]},{"id":"canh-dong-hoang-hai-cot-truoc-chien-truong-vien-co","name":"Cánh đồng hoang trước Chiến trường viễn cổ","cn":"","capDo":"khac","parentId":"chien-truong-vien-co","blurb":"Vùng đồng hoang đầy hài cốt nằm trước Chiến trường viễn cổ, nơi Yêu Vệ Địa Ma phục kích Vương Lâm.","detail":"Cánh đồng hoang phủ đầy hài cốt nằm án ngữ trước lối vào Chiến trường viễn cổ. Khi Vương Lâm vượt Vạn Yêu sơn tiến tới, Yêu Vệ Địa Ma từ dưới đất chui lên phục kích, đâm kim đất tứ phía rồi triển khai thần thông Thiên Nùng và Thiên Trướng Địa Đông, biến cả khu vực thành quả cầu chất dịch khổng lồ vây Vương Lâm bên trong. Trận chiến kết thúc với Phong Ngâm tử vong và lão già bị thương nặng.","theLucLienQuan":[],"nguon":["@c0561"]},{"id":"tieu-tinh-ban-toc-hong","name":"Tiểu tinh bản tôn tóc hồng","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tiểu tinh bán phế cách Đông Hải chi môn vô số dặm, nơi bản tôn tóc hồng của Vương Lâm trấn thủ.","detail":"Một tiểu tinh cầu bán phế nằm cách Đông Hải chi môn vô số dặm. Trên tinh cầu này có bản tôn tóc hồng của Vương Lâm đang trấn giữ. Khi Vương Lâm ở Yêu Linh chi địa lĩnh ngộ Cổ Thần thuật và đánh ra ấn quyết, bản tôn trên tiểu tinh này đột nhiên mở mắt, mi tâm lóe tinh mang, hô “Thu!” khiến linh lực sâu trong lòng tinh cầu phun ra quy về thân.","theLucLienQuan":[],"nguon":["@c0565"]},{"id":"hoang-tuyen-huyen-canh","name":"Hoàng Tuyền (sông huyễn)","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Con sông huyễn cảnh do Vương Lâm bày ra, chứa vô số tay chân cụt và tiếng than khóc.","detail":"Hoàng Tuyền là một con sông huyễn cảnh do Vương Lâm bấm quyết huyễn hóa trong trận chiến với tán ma chiếm xác đại hán. Trong sông tràn ngập tay chân cụt và tiếng than khóc thê lương. Vương Lâm ném gần như toàn bộ pháp bảo của mình vào Hoàng Tuyền — Tôn Hồn Phiên, Cấm Phiên, tiên kiếm Hứa Lập Quốc, loan đao, Côn Cực Tiên, vỏ kiếm, Mạt Dương chi kiếm — chỉ giữ lại Xạ Thần Xa và cuộn tranh thần bí. Sau đó hắn rút Hoàng Tuyền hóa thành một đạo hoàng mang ẩn chứa cả pháp bảo lẫn đạo của hắn.","theLucLienQuan":[],"nguon":["@c0565"]},{"id":"canh-dong-hoang-hai-cot-q06","name":"Cánh đồng hoang đầy hài cốt","capDo":"khac","parentId":"chien-truong-vien-co","blurb":"Cánh đồng hoang ngập hài cốt nằm trước chiến trường viễn cổ, nơi Yêu Vệ Địa Ma phục kích Vương Lâm.","detail":"Vùng đất hoang vu trải đầy hài cốt nằm trên đường từ Vạn Yêu sơn dẫn vào chiến trường viễn cổ. Tại đây, Yêu Vệ Địa Ma từ dưới đất chui lên phục kích Vương Lâm, thi triển thần thông Thiên Nùng và Thiên Trướng Địa Đông tạo quả cầu chất dịch khổng lồ vây nhốt hắn. Mặt đất tại đây từng bị rúng động, xuất hiện lỗ hổng giống vết lở loét rồi nổ tung phun chất lỏng dày mười trượng khi lão già hắc y thi triển thần thông Địa Tích.","theLucLienQuan":[],"nguon":["@c0561"]}]};
